class Solution {
    public long maximumOr(int[] nums, int k) {
        long maxOr = 0;
        for (int i = 0; i < nums.length; i++) {
            maxOr |= nums[i];
        }
        int bits = 30;
        while (k > 0 && bits >= 0) {
            int canChange = 0;
            for (int num : nums) {
                if (((num >> bits) & 1) == 0) {
                    canChange++;
                }
            }
            if (canChange <= k) {
                k -= canChange;
                maxOr |= (1L << bits);
            }
            bits--;
        }
        return maxOr;
    }
}
```
